INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '90a50e29-0681-444b-b410-ce54254e2711',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Equivalents to Snowflake's Four Core Features: Warehouses, Cloning, Time Travel & Sharing$escape$,
  $escape$Snowflake's flagship features map directly to Databricks primitives — and Delta Lake often extends them further.

**Virtual Warehouses → SQL Warehouses:** Databricks SQL Warehouses (serverless or pro tier) auto-scale like Snowflake's multi-cluster warehouses. Key difference: all warehouses share one Delta Lake storage layer, eliminating the per-warehouse result cache divergence Snowflake users work around.

**Zero-Copy Cloning → `SHALLOW CLONE`:** Snowflake clones reference original micropartitions. Databricks' `SHALLOW CLONE` creates a metadata-only pointer via the Delta transaction log. Writes to the clone generate new Parquet files without touching source data — same semantic, open format.

**Time Travel → Delta Time Travel:** Both use point-in-time queries, but Databricks exposes `VERSION AS OF` (by transaction ID) and `TIMESTAMP AS OF`. Retention defaults to 30 days, tunable via `delta.logRetentionDuration`. `DESCRIBE HISTORY` gives full audit lineage — no Snowflake equivalent for transaction-level inspection.

**Data Sharing → Delta Sharing:** Snowflake sharing locks both sides into Snowflake. Delta Sharing is an open protocol — external consumers query live Delta tables over HTTPS from Spark, pandas, Power BI, or DuckDB with no Databricks account required.$escape$,
  $escape$-- Zero-copy clone: metadata-only, no Parquet copied
CREATE TABLE prod.orders_clone
SHALLOW CLONE prod.orders;

-- Time travel by version ID
SELECT * FROM prod.orders VERSION AS OF 42;

-- Time travel by timestamp
SELECT * FROM prod.orders
TIMESTAMP AS OF '2025-01-15T00:00:00';

-- Full transaction audit log (no Snowflake equivalent)
DESCRIBE HISTORY prod.orders;

-- Delta Sharing: expose table to external consumers
CREATE SHARE orders_share;
ALTER SHARE orders_share ADD TABLE prod.orders;
CREATE RECIPIENT external_partner USING ID 'databricks:...';
ALTER SHARE orders_share ADD RECIPIENT external_partner;$escape$,
