INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f1e200e2-c670-467f-ac01-abf6558d719a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks + BigQuery — Pulling Data Without Blowing Your Slot Budget$escape$,
  $escape$When Databricks reads from BigQuery via the Spark-BigQuery connector, every query hits BigQuery's compute model — either on-demand (per-TB scanned) or reserved slots. Understanding this prevents surprise bills. BigQuery partitioning and clustering are your primary cost levers: a partitioned table on `event_date` lets BigQuery prune entire partition blocks before scanning; clustering on high-cardinality columns like `user_id` further colocates data so range filters skip irrelevant micro-partitions. Critically, Spark pushdown predicates are honored by the connector — but only for partition filters and simple column predicates. Complex Spark expressions (UDFs, non-sargable conditions) do NOT push down, causing full table scans regardless of your BigQuery clustering. To control slot consumption from Databricks jobs, always pass `.option("filter", "...")` explicitly rather than relying on Spark's lazy filter pushdown. For recurring pipelines, prefer BigQuery slot reservations over on-demand — a 100-slot baseline reservation is dramatically cheaper than repeated on-demand scans of multi-TB tables. Use `INFORMATION_SCHEMA.JOBS` in BigQuery to audit which Databricks jobs consumed the most slots.$escape$,
  $escape$# Databricks notebook — cost-efficient BigQuery read
df = (
    spark.read
    .format("bigquery")
    .option("parentProject", "my-gcp-project")
    .option("table", "my_project.analytics.events")
    # Explicit partition filter — guarantees pushdown, avoids full scan
    .option("filter", "event_date BETWEEN '2024-01-01' AND '2024-03-31'")
    .option("createDisposition", "CREATE_NEVER")
    .load()
)

# Project early — reduces bytes transferred to Databricks cluster
(
    df.select("user_id", "event_type", "event_date", "revenue_usd")
    .write.format("delta")
    .partitionBy("event_date")
    .saveAsTable("main.bronze.bq_events")
)$escape$,
  $escape$python$escape$,
