INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7547d00e-3b48-4b9f-8896-c1a1c568cfdb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks — Redshift Concepts Mapped to Delta Lake (Distribution, Sort Keys, VACUUM)$escape$,
  $escape$If you're migrating from Redshift or reading its docs, the mental model differs sharply from Delta Lake. Redshift's distribution keys control data co-location across slices — in Databricks, you get this via `PARTITIONED BY` on high-cardinality columns or `DISTRIBUTE BY` in Spark SQL joins. Redshift compound/interleaved sort keys map to Delta's `ZORDER BY` in `OPTIMIZE` commands — Z-ordering clusters correlated columns together using space-filling curves, unlike Redshift's sequential sort. For Redshift's `VACUUM` (reclaims space after deletes/updates) + `ANALYZE` (refreshes column stats), Delta Lake splits this into two explicit operations: `VACUUM` removes unreferenced Parquet files older than the retention threshold (default 7 days), while `ANALYZE TABLE` regenerates column-level statistics the optimizer uses for predicate pushdown and join reordering. Redshift RA3 nodes decouple compute from managed storage (S3) — Databricks operates the same way natively via cloud object storage, so you never size storage separately. Use `OPTIMIZE` + `ZORDER` together on frequently-filtered columns post-ingestion; skip both on append-only event tables where full scans dominate.$escape$,
  $escape$-- Databricks SQL equivalents of Redshift maintenance operations

-- Equivalent of Redshift VACUUM SORT ONLY (reorganize + Z-order clustering)
OPTIMIZE catalog.schema.events
ZORDER BY (user_id, event_date);

-- Equivalent of Redshift ANALYZE (refresh column stats for query optimizer)
ANALYZE TABLE catalog.schema.events
COMPUTE STATISTICS FOR ALL COLUMNS;

-- Equivalent of Redshift VACUUM DELETE ONLY (purge stale Delta versions)
VACUUM catalog.schema.events RETAIN 168 HOURS;

-- Equivalent of Redshift distribution key (partition for co-location)
CREATE TABLE catalog.schema.events (
  user_id BIGINT,
  event_date DATE,
  payload STRING
)
PARTITIONED BY (event_date)
USING DELTA;$escape$,
