INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fedcebb2-8463-4f17-8dd1-e72584b3e420',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Delta Lake — Incremental CDC with Change Data Feed$escape$,
  $escape$Delta Lake's Change Data Feed (CDF) exposes row-level change operations — insert, update_preimage, update_postimage, delete — without full table scans. Enable it once per table and every subsequent write appends a change log that downstream jobs can read incrementally.

This is the backbone of low-latency CDC pipelines in Databricks. Instead of diffing snapshots, you read only what changed since a given version or timestamp. `update_postimage` gives you the committed row state after an update; `update_preimage` gives the before-state — useful for audit trails or GDPR right-to-erasure verification.

CDF pairs natively with Structured Streaming: set `readChangeFeed` to `true` on a streaming reader and Databricks automatically tracks the latest processed version in the checkpoint. Photon accelerates the underlying Delta log replay, so high-churn tables stay fast.

Avoid enabling CDF on append-only tables — the overhead is real and the change log grows with every write. Use `DESCRIBE HISTORY` to inspect version numbers before setting `startingVersion` in production jobs.$escape$,
  $escape$# Enable CDF on an existing Unity Catalog table
spark.sql("""
  ALTER TABLE catalog.schema.user_events
  SET TBLPROPERTIES (delta.enableChangeDataFeed = true)
""")

# Batch read: changes since version 12
changes = (
    spark.read
        .format("delta")
        .option("readChangeFeed", "true")
        .option("startingVersion", 12)
        .table("catalog.schema.user_events")
)

# Keep only post-update and insert rows
changes.filter(
    "_change_type IN ('insert', 'update_postimage')"
).select("user_id", "event_type", "_commit_timestamp").show()$escape$,
  $escape$python$escape$,
