INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '50d7b04f-fb57-48e9-80d4-e4bdc10f4637',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Data Modeling — Star Schema vs Wide Tables in the Gold Layer$escape$,
  $escape$In Databricks, wide tables typically outperform star schemas in the gold layer. Delta Lake's columnar Parquet storage eliminates the join-overhead argument for normalization — Photon's vectorized engine scans wide tables without the shuffle cost of multi-table joins. Star and snowflake schemas still win when dimensions are shared across multiple fact tables; use Unity Catalog to register those dimension tables as governed assets across workspaces and catalogs.

For star schemas, ZORDER BY on your primary join keys co-locates matching data files, cutting file scans on JOIN predicates by 60–80% in practice. Schedule OPTIMIZE via Databricks Workflows to keep Z-ordering effective after incremental loads.

For wide (denormalized) tables, partition by a high-cardinality time column (e.g., event_date) and ZORDER on your most-filtered attribute (e.g., region). Avoid partitioning on low-cardinality columns like status — Delta's file skipping already handles those efficiently.

Before committing to either strategy, run EXPLAIN and DESCRIBE DETAIL in Databricks SQL to confirm file skipping is actually reducing scan size under your real query patterns.$escape$,
  $escape$-- Star schema: fact table optimized for dimension joins
CREATE OR REPLACE TABLE gold.fact_orders
USING DELTA PARTITIONED BY (order_date)
AS SELECT * FROM silver.orders;

OPTIMIZE gold.fact_orders ZORDER BY (customer_id, product_id);

-- Wide table: pre-joined for BI/dashboard workloads
CREATE OR REPLACE TABLE gold.wide_orders
USING DELTA PARTITIONED BY (order_date)
AS
SELECT o.*, c.region, c.segment, p.category, p.brand
FROM silver.orders o
JOIN silver.customers c USING (customer_id)
JOIN silver.products  p USING (product_id);

OPTIMIZE gold.wide_orders ZORDER BY (region, category);$escape$,
