INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6b2acfa5-e26f-4914-9db9-6c0949739a2d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Partitioning & Clustering — Stop Scanning Tables You Don't Need To$escape$,
  $escape$Delta Lake partition pruning eliminates entire file directories before a single row is read — but only when your filter column matches the partition column exactly. Partitioning on high-cardinality columns like `user_id` creates millions of small files (the small-file problem), tanking both write and read performance. Reserve partitioning for low-cardinality, frequently-filtered columns like `event_date` or `region`.

For high-cardinality filtering, use Liquid Clustering (`CLUSTER BY`) instead — introduced in Databricks Runtime 13.3. It uses Z-order-style co-location without static directory partitions, adapts to changing query patterns via `OPTIMIZE`, and avoids partition explosion entirely.

Check whether pruning is actually firing: in the Spark UI, a pruned scan shows `numFiles` far below total — if it equals total, your predicate isn't aligning with partition boundaries. Watch for implicit casts (`date_trunc` on a `DATE` partition column) silently disabling pruning. Always match filter expression type to the partition column type precisely.$escape$,
  $escape$-- Legacy: static date partitioning
CREATE TABLE events (
  event_id STRING,
  user_id STRING,
  payload STRING
) USING DELTA
PARTITIONED BY (event_date DATE);

-- Modern: Liquid Clustering (DBR 13.3+) — no partition explosion
CREATE TABLE events (
  event_id STRING,
  user_id STRING,
  event_date DATE,
  payload STRING
) USING DELTA
CLUSTER BY (user_id, event_date);

-- Incrementally recluster after bulk writes
OPTIMIZE events;$escape$,
  $escape$sql$escape$,
