INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '01ea14ef-0dba-467b-a3fd-57870042b05c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Cost Management — Query Estimation, DBU Consumption, and Materialized Views$escape$,
  $escape$Databricks bills in DBUs (Databricks Units) — every SQL warehouse query consumes them based on warehouse size (2X-Small to 4X-Large) and runtime. Run EXPLAIN COST before executing multi-table joins on large Delta tables; it surfaces plan cardinalities and shuffle operations that are the primary DBU drivers, even without giving a direct DBU estimate.

For recurring aggregations powering dashboards or BI tools, Databricks Materialized Views (Unity Catalog required) are the highest-leverage cost lever. Unlike standard views that re-execute on every query hit, MVs persist computed results and refresh incrementally using Delta log checkpointing — dramatically reducing scanned rows and DBU spend per query.

Audit actual consumption via system.billing.usage (SKU, DBU quantity, workspace ID) and cross-reference with system.query.history to pinpoint expensive query patterns. Serverless SQL warehouses eliminate idle DBU burn by scaling to zero between queries. Complement with ZORDER on high-cardinality filter columns to minimize file scans, and enforce cluster policies with DBU-per-hour caps to prevent runaway spend on shared workspaces.$escape$,
  $escape$-- Materialize expensive aggregation (requires Unity Catalog)
CREATE MATERIALIZED VIEW catalog.schema.daily_event_counts
AS
SELECT event_date, event_type, COUNT(*) AS event_count
FROM catalog.schema.events
GROUP BY event_date, event_type;

-- Trigger incremental refresh from Delta log
REFRESH MATERIALIZED VIEW catalog.schema.daily_event_counts;

-- Audit DBU burn by SKU over the last 7 days
SELECT sku_name, SUM(usage_quantity) AS total_dbus
FROM system.billing.usage
WHERE usage_date >= DATEADD(DAY, -7, CURRENT_DATE())
GROUP BY sku_name ORDER BY total_dbus DESC;$escape$,
