INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4f793613-e5fe-4c31-b027-105c4066495c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Data Quality — Null Handling, Deduplication, and Constraints at Scale$escape$,
  $escape$Delta Lake's CHECK constraints and NOT NULL constraints enforce data quality at write time — any violating row raises an AnalysisException and aborts the transaction, keeping bad data out of your table entirely. Define them with ALTER TABLE t ADD CONSTRAINT valid_status CHECK (status IN ('active', 'inactive')). For null handling in ETL, use DataFrame.na.fill() with column-specific defaults or coalesce() in SQL to substitute sentinel values before writing. Deduplication is best handled with MERGE INTO using a deterministic key — match on composite keys, update on conflict, insert on new. For streaming deduplication, enable dropDuplicates() on a watermarked column before the sink write, combined with a trigger.availableNow() for batch-style micro-batch control. Unity Catalog adds a layer via table-level data quality expectations through Lakehouse Monitoring, letting you define freshness, volume, and custom metric rules that surface anomalies in the system.information_schema. Combine constraints + MERGE + Monitoring for a defense-in-depth quality pipeline.$escape$,
  $escape$-- Enforce constraints at table level
ALTER TABLE orders ADD CONSTRAINT valid_status CHECK (status IN ('pending', 'shipped', 'cancelled'));
ALTER TABLE orders CHANGE COLUMN customer_id customer_id BIGINT NOT NULL;

-- Idempotent deduplication via MERGE
MERGE INTO orders AS target
USING (
  SELECT * FROM raw_orders
  QUALIFY ROW_NUMBER() OVER (PARTITION BY order_id ORDER BY updated_at DESC) = 1
) AS source
ON target.order_id = source.order_id
WHEN MATCHED THEN UPDATE SET *
WHEN NOT MATCHED THEN INSERT *;$escape$,
  $escape$sql$escape$,
