INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1505258-4821-475e-b362-473cf2ca97cc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Unity Catalog — Row Filters, Column Masks, and RBAC Done Right$escape$,
  $escape$Unity Catalog is Databricks' single governance layer across all workspaces. Access control operates at three levels: catalog, schema, and table — each granting privileges to users, service principals, or groups via GRANT statements.

For row-level security, Unity Catalog uses row filter functions. You define a SQL function that returns a boolean, then bind it to a table with ALTER TABLE ... SET ROW FILTER. At query time, Databricks injects the filter automatically — no view wrappers needed. The function can call IS_MEMBER() or CURRENT_USER() to scope rows per principal.

Column-level security uses column masks, similarly bound via ALTER TABLE ... ALTER COLUMN ... SET MASK. The mask function receives the column value and returns either the real value or a redacted version based on group membership. Unlike traditional VIEWs, masks and filters survive table renames and are enforced even on Delta sharing exports.

For RBAC, avoid granting directly to users — always use groups synced from your IdP via SCIM. Combine with data owner patterns: catalog admins own schemas, team leads own tables, analysts get SELECT only.$escape$,
  $escape$-- Row filter: analysts only see their region's data
CREATE FUNCTION catalog.security.region_filter(region STRING)
  RETURN region = current_user_region() OR IS_ACCOUNT_GROUP_MEMBER('data-admins');

ALTER TABLE catalog.sales.orders
  SET ROW FILTER catalog.security.region_filter ON (region);

-- Column mask: hide raw PII from non-PII roles
CREATE FUNCTION catalog.security.mask_email(email STRING)
  RETURN CASE WHEN IS_ACCOUNT_GROUP_MEMBER('pii-access')
    THEN email ELSE regexp_replace(email, '(.).+(@.+)', '$1***$2') END;

ALTER TABLE catalog.sales.customers
  ALTER COLUMN email SET MASK catalog.security.mask_email;

-- RBAC: grant SELECT to analyst group, never to individuals
GRANT SELECT ON TABLE catalog.sales.orders TO `data-analysts`;$escape$,
