INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '52a849f1-b356-43fb-806b-01aaf73a51b6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Query Performance — Delta Caching, Materialized Views, and AQE$escape$,
  $escape$Databricks offers three distinct caching layers that most engineers conflate. Delta Cache (disk-based, automatic on DBR clusters) decompresses and stores Parquet data locally — it's not the same as Spark's in-memory `CACHE TABLE`. Enable it explicitly with `spark.databricks.io.cache.enabled true` and size it via `spark.databricks.io.cache.maxDiskUsage`. For repeated aggregations, Databricks SQL Materialized Views persist results and refresh incrementally on Delta tables using `CREATE OR REFRESH MATERIALIZED VIEW`. Unlike standard views, they push computation to refresh time, not query time — critical for BI workloads hitting the same rollup repeatedly. Adaptive Query Execution (AQE) is on by default in DBR 7.3+: it re-optimizes mid-flight based on shuffle partition statistics. Force broadcast joins for small tables with `spark.sql.autoBroadcastJoinThreshold 10485760`. For skewed joins, `spark.sql.adaptive.skewJoin.enabled true` splits hot partitions automatically. Profile bottlenecks via the Spark UI's SQL tab — look for `PhotonShuffleExchangeSink` stages; those are your rewrite targets.$escape$,
  $escape$-- Create a Databricks SQL materialized view for daily active users
CREATE OR REFRESH MATERIALIZED VIEW gold.daily_active_users
AS
SELECT
  DATE_TRUNC('day', event_time) AS event_date,
  COUNT(DISTINCT user_id)       AS dau
FROM silver.events
WHERE event_type = 'session_start'
GROUP BY 1;

-- Force AQE skew join handling and cap broadcast threshold
SET spark.sql.adaptive.skewJoin.enabled = true;
SET spark.sql.autoBroadcastJoinThreshold = 10485760; -- 10 MB

-- Verify Delta Cache is active on the cluster
SET spark.databricks.io.cache.enabled = true;$escape$,
  $escape$sql$escape$,
