INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '565268d2-08f5-451b-817a-102a687ac39f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Delta Sharing — Cross-Account Data Without Copying$escape$,
  $escape$Delta Sharing is Databricks' open protocol for sharing live data across accounts, clouds, and even non-Databricks recipients — no data duplication, no ETL pipelines. On the provider side, you create a Share, add tables or partitions, then grant it to a Recipient backed by either Unity Catalog (for Databricks-to-Databricks) or a token-based profile (for open clients). Recipients query data directly against your Delta Lake — they always see the latest version without you pushing anything. For sensitive columns, use secure views: define a view in your metastore that masks or filters rows, then share the view instead of the base table. Unity Catalog enforces column-level and row-level filters transparently. On the Databricks Marketplace, you can publish a Share as a listing — consumers discover and mount it in one click via `CREATE CATALOG USING SHARE`. No S3 bucket policies, no cross-account IAM roles, no scheduled exports. Access is revocable instantly by dropping the recipient or rotating its activation link.$escape$,
  $escape$-- Provider: create and populate a share
CREATE SHARE prod_analytics_share;

ALTER SHARE prod_analytics_share
  ADD TABLE catalog.sales.orders
  PARTITION (region = 'us-east-1');

-- Add a secure view instead of raw table
ALTER SHARE prod_analytics_share
  ADD VIEW catalog.sales.orders_masked;

-- Grant to a Unity Catalog recipient (cross-account)
CREATE RECIPIENT acme_corp
  USING ID 'databricks://acme.azuredatabricks.net/metastoreId';

GRANT SELECT ON SHARE prod_analytics_share TO RECIPIENT acme_corp;

-- Consumer mounts it as a local catalog
CREATE CATALOG acme_shared USING SHARE provider_metastore.prod_analytics_share;$escape$,
  $escape$sql$escape$,
