INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3a959d36-1cb4-4164-bb09-43aaa2896f0f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Incremental Loading — Append vs Upsert and When to Use Each$escape$,
  $escape$Delta Lake gives you two primary incremental patterns. Append-only works when source records are immutable — structured streaming with `trigger(availableNow=True)` writes new rows directly, zero merge overhead. Use `COPY INTO` for batch file ingestion with automatic deduplication via `COPY_OPTIONS ('mergeSchema' = 'true')`.

For mutable sources, Delta's `MERGE INTO` handles upserts atomically. Pair it with CDC feeds from Debezium or DMS: filter `op = 'D'` rows for deletes, `op = 'U'`/`'I'` for upserts. The merge evaluates on matched/not-matched clauses in a single scan — no separate delete pass.

Delta Live Tables abstracts this further: declare a `STREAMING TABLE` with `apply_changes()` to handle CDC automatically, respecting sequence ordering via a `sequence_by` column to resolve late-arriving events.

Performance tip: Z-ORDER your merge key columns and set `delta.targetFileSize` to reduce small file amplification on high-frequency upsert workloads. Use `OPTIMIZE` + `VACUUM` post-merge to reclaim storage from superseded file versions.$escape$,
  $escape$-- CDC upsert pattern using Delta MERGE
MERGE INTO silver.customers AS target
USING (
  SELECT * FROM bronze.customers_cdc
  WHERE op IN ('I', 'U', 'D')
) AS source
ON target.customer_id = source.customer_id
WHEN MATCHED AND source.op = 'D' THEN DELETE
WHEN MATCHED AND source.op = 'U' THEN
  UPDATE SET *
WHEN NOT MATCHED AND source.op = 'I' THEN
  INSERT *;$escape$,
  $escape$sql$escape$,
