INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '335f8b6f-0bc4-4b37-840e-25c0b07d02c3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks Delta Lake — Taming JSON and Schema Evolution with Semi-Structured Data$escape$,
  $escape$Databricks natively handles JSON ingestion via `cloudFiles` with Auto Loader, but the real power comes from combining `VARIANT` type (DBR 15+) with Delta Lake's schema evolution. For nested JSON, `from_json()` with an explicit schema beats `schema_of_json()` inference on production data — inference scans the entire dataset and misses nulls in sparse fields.

For Parquet with evolving schemas, enable `mergeSchema` at the write level or set `spark.databricks.delta.schema.autoMerge.enabled = true` cluster-wide. Delta tracks schema changes in its transaction log, so time-travel queries (`VERSION AS OF`) still respect the original schema at that point.

For deeply nested structs, use `schema_of_json()` once offline to generate a baseline, then hardcode it. Explode arrays with `explode_outer()` (not `explode`) to preserve rows with empty arrays — a silent data-loss footgun in ETL pipelines. Use `posexplode` when order within the array carries semantic meaning.$escape$,
  $escape$from pyspark.sql.functions import from_json, explode_outer, col
from pyspark.sql.types import StructType, StructField, StringType, ArrayType

event_schema = StructType([
    StructField("user_id", StringType()),
    StructField("tags", ArrayType(StringType())),
    StructField("meta", StructType([
        StructField("source", StringType()),
        StructField("version", StringType())
    ]))
])

df = spark.readStream.format("cloudFiles") \
    .option("cloudFiles.format", "json") \
    .option("cloudFiles.schemaLocation", "/mnt/checkpoints/schema") \
    .load("/mnt/raw/events")

parsed = df.withColumn("data", from_json(col("value"), event_schema)) \
    .select("data.*")

flattened = parsed.select(
    col("user_id"),
    col("meta.source").alias("source"),
    explode_outer(col("tags")).alias("tag")
)

flattened.writeStream.format("delta") \
    .option("mergeSchema", "true") \
    .option("checkpointLocation", "/mnt/checkpoints/events") \
    .toTable("catalog.silver.events")$escape$,
  $escape$python$escape$,
