INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ba7f2ddd-dd3b-4c61-bb9d-abf93e70b85c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks as an Integration Hub — dbt, Airflow, BI Tools, and Reverse ETL$escape$,
  $escape$Databricks sits at the center of the modern data stack, exposing clean integration points at every layer. For dbt, use the `dbt-databricks` adapter (not `dbt-spark`) — it supports Unity Catalog three-part naming (`catalog.schema.model`) and pushes compute to a SQL Warehouse via HTTP path, not a cluster. For Airflow, `DatabricksRunNowOperator` triggers existing Jobs by `job_id`, while `DatabricksSubmitRunOperator` submits ad-hoc task specs — both authenticate via Personal Access Token or OAuth M2M stored in an Airflow connection. BI tools (Tableau, Power BI, Looker) connect through Databricks SQL Warehouse JDBC/ODBC endpoints; Partner Connect auto-provisions these with correct driver versions. For reverse ETL (Census, Hightouch), point the source at a SQL Warehouse endpoint and grant `SELECT` on Unity Catalog tables — avoid direct cluster connections since warehouses auto-suspend and scale independently. Delta Sharing is the zero-copy alternative when the destination supports it, skipping the ETL layer entirely.$escape$,
  $escape$# profiles.yml — dbt-databricks (not dbt-spark)
my_project:
  target: prod
  outputs:
    prod:
      type: databricks
      catalog: main          # Unity Catalog catalog
      schema: analytics
      host: adb-<workspace-id>.azuredatabricks.net
      http_path: /sql/1.0/warehouses/<warehouse-id>
      token: "{{ env_var('DBT_DATABRICKS_TOKEN') }}"
      threads: 8$escape$,
  $escape$bash$escape$,
