INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ff517991-8611-4a19-a43d-48c66077533d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Databricks — A Decision Framework for Choosing It Over Snowflake, BigQuery, or Redshift$escape$,
  $escape$Databricks wins when your workload crosses the ML/data engineering boundary. If your pipeline ends at a dashboard, Snowflake or BigQuery will serve you with less operational overhead. The calculus shifts the moment you need Delta Lake's ACID transactions on open Parquet, MLflow experiment tracking, or Feature Store to share features between training and serving.

Choose Databricks when:
- You run Structured Streaming into Delta Live Tables for declarative, auto-scaling pipelines
- Unity Catalog governs both your BI tables and ML feature tables under one ACL — no separate governance plane
- Photon-accelerated SQL Warehouses serve analysts on the same Delta tables your PySpark jobs write — zero data movement or format conversion
- Delta Sharing lets you publish data externally without forcing consumers to acquire a Snowflake seat

Choose Snowflake when your team is SQL-native and ML happens in a separate system. BigQuery if you're serverless-first on GCP with pay-per-query economics. Redshift if you're deep in AWS and rely on Spectrum for S3 federation.

The tell: if an MLflow run and a Databricks SQL dashboard will ever share the same Unity Catalog table, Databricks is your control plane.$escape$,
  $escape$import dlt
from pyspark.sql import functions as F

# DLT table registered in Unity Catalog — consumed by both Feature Store and BI
@dlt.table(
    name="main.data_warehouse.user_features",
    comment="Shared by ML Feature Store and Databricks SQL dashboards",
    table_properties={"delta.enableChangeDataFeed": "true"}
)
def user_features():
    return (
        dlt.read("main.bronze.events")
            .groupBy("user_id")
            .agg(
                F.count("event_id").alias("event_count_30d"),
                F.avg("session_duration").alias("avg_session_duration")
            )
    )$escape$,
  $escape$python$escape$,
